import Foundation
import CoreData

extension ContactEntity {
    @nonobjc nonisolated public class func fetchRequest() -> NSFetchRequest<ContactEntity> {
        return NSFetchRequest<ContactEntity>(entityName: "ContactEntity")
    }

    @NSManaged public var id: UUID
    @NSManaged public var compositeName: String?
    @NSManaged public var givenName: String?
    @NSManaged public var familyName: String?
    @NSManaged public var phoneE164: String?
    @NSManaged public var notes: String?
    @NSManaged public var createdAt: Date
    @NSManaged public var externalIdentifier: String?
    @NSManaged public var imageThumbData: Data?
    @NSManaged public var organization: String?
    @NSManaged public var email: String?
    @NSManaged public var address: String?
    @NSManaged public var facetimeHandle: String?
    @NSManaged public var isSelf: Bool
    @NSManaged public var lastLatitude: NSNumber?
    @NSManaged public var lastLongitude: NSNumber?
    @NSManaged public var lastLocationAccuracyMeters: NSNumber?
    @NSManaged public var lastLocationAt: Date?
    @NSManaged public var birthday: Date?
    @NSManaged public var isPrimaryForSouvenir: Bool
    @NSManaged public var ring: Int16
    @NSManaged public var ringOrder: Int16
    @NSManaged public var cloudKitUserRecordID: String?

    // Relationships
    @NSManaged public var photos: Set<PhotoEntity>?
    @NSManaged public var primarySouvenir: SouvenirEntity?
}

extension ContactEntity: Identifiable {}

extension ContactEntity {
    public var photosArray: [PhotoEntity] {
        let set = photos ?? []
        return set.sorted { ($0.timestamp ?? Date.distantPast) > ($1.timestamp ?? Date.distantPast) }
    }
}

extension ContactEntity {
    var zodiacEnum: ZodiacCalculator.ZodiacSign? {
        guard let birthday = self.birthday else { return nil }
        let calculator = ZodiacCalculator()
        return calculator.getZodiacSign(for: birthday)
    }

    public var zodiacSign: (emoji: String, name: String)? {
        guard let sign = zodiacEnum else { return nil }
        return (sign.emoji, sign.rawValue)
    }

    public var birthdayDisplayString: String? {
        guard let birthday = self.birthday else { return nil }

        var calendar = Calendar(identifier: .gregorian)
        calendar.timeZone = .current
        let today = calendar.startOfDay(for: Date())

        let birthdayDay = calendar.startOfDay(for: birthday)
        let components = calendar.dateComponents([.year, .month, .day], from: birthdayDay, to: today)
        let age = components.year ?? 0

        let nextBirthdayComponents = DateComponents(
            year: calendar.component(.year, from: today),
            month: calendar.component(.month, from: birthdayDay),
            day: calendar.component(.day, from: birthdayDay)
        )
        var nextBirthday = calendar.date(from: nextBirthdayComponents) ?? today

        if nextBirthday < today {
            nextBirthday = calendar.date(byAdding: .year, value: 1, to: nextBirthday) ?? nextBirthday
        }

        let daysUntilBirthday = calendar.dateComponents([.day], from: today, to: nextBirthday).day ?? 0

        if daysUntilBirthday == 0 {
            return "🎂 Happy Birthday! (Turned \(age))"
        } else if daysUntilBirthday <= 7 {
            return "🎂 Birthday in \(daysUntilBirthday) days"
        } else {
            let formatter = DateFormatter()
            formatter.dateFormat = "MMM d"
            formatter.timeZone = .current
            return "🎂 \(formatter.string(from: birthdayDay)) (Age \(age))"
        }
    }
}

