import Foundation
import CoreData

@objc(ContactEntity)
public class ContactEntity: NSManagedObject {
    /// Ensure required defaults are set on insert
    public override func awakeFromInsert() {
        super.awakeFromInsert()
        id = UUID()
        createdAt = Date()
    }

    /// Computed display name from compositeName or fallback to givenName + familyName.
    public var displayName: String {
        if let composite = compositeName, !composite.isEmpty {
            return composite
        }
        let parts = [givenName, familyName].compactMap { $0 }.filter { !$0.isEmpty }
        if !parts.isEmpty { return parts.joined(separator: " ") }
        if let org = organization, !org.isEmpty { return org }
        if let phone = phoneE164, !phone.isEmpty { return phone }
        return "Unknown Contact"
    }

    /// Thumbnail image from stored data.
    public var thumbnailImage: Data? {
        return imageThumbData
    }

    // MARK: - Core Data Validation (Phase 14)

    /// Validate entity before saving (Core Data validation)
    /// - Throws: ValidationError if validation fails
    public override func validateForInsert() throws {
        try ValidationService.validateContact(self)
    }

    /// Validate entity before update (Core Data validation)
    /// - Throws: ValidationError if validation fails
    public override func validateForUpdate() throws {
        if managedObjectContext?.userInfo["svnrSkipUpdateValidation"] as? Bool == true {
            return
        }
        try ValidationService.validateContact(self)
    }

    /// Validate entity before delete (Core Data validation)
    /// - Throws: ValidationError if validation fails
    public override func validateForDelete() throws {
        if managedObjectContext?.userInfo["svnrSkipDeleteValidation"] as? Bool == true {
            return
        }
        // Check if contact is primary for any souvenir
        if let _ = primarySouvenir {
            throw ValidationError.custom("Cannot delete contact that is primary for a souvenir")
        }
    }
}

