import Foundation
import CoreData

/// Handles drag-to-reorder logic with ring overflow cascade.
/// When a contact is dragged to a new position, this service updates ringOrder values
/// and cascades contacts to lower rings if needed.
class RingOrderService {
    private let viewContext: NSManagedObjectContext

    init(viewContext: NSManagedObjectContext) {
        self.viewContext = viewContext
    }

    /// Reorder contact from old position to new position with cascade handling.
    /// - Parameters:
    ///   - contact: Contact being moved
    ///   - fromRingOrder: Current ringOrder position
    ///   - toRingOrder: New ringOrder position
    /// - Returns: List of contacts whose ring changed due to cascade
    func reorderContact(
        _ contact: ContactEntity,
        from fromRingOrder: Int16,
        to toRingOrder: Int16
    ) throws -> [ContactEntity] {
        guard fromRingOrder != toRingOrder else { return [] }

        let isMovingUp = toRingOrder < fromRingOrder
        var affectedContacts: [ContactEntity] = []

        if isMovingUp {
            // Moving UP: contact enters a potentially full ring
            affectedContacts = try handleMoveUp(contact, from: fromRingOrder, to: toRingOrder)
        } else {
            // Moving DOWN: no cascade needed
            affectedContacts = try handleMoveDown(contact, from: fromRingOrder, to: toRingOrder)
        }

        try viewContext.save()
        return affectedContacts
    }

    /// Moving a contact UP (to a lower ringOrder number).
    /// If target ring is full, the lowest contact in that ring cascades to the next ring.
    private func handleMoveUp(
        _ contact: ContactEntity,
        from: Int16,
        to: Int16
    ) throws -> [ContactEntity] {
        var affected: [ContactEntity] = []
        let targetRing = Ring.from(ringOrder: to)
        let targetCapacity = targetRing.capacity

        // Fetch all contacts in the target ring at current state
        let targetRingContacts = try fetchContactsInRing(targetRing)
        let targetRingCount = targetRingContacts.count

        // If target ring is full, cascade the lowest one out
        if targetRingCount >= targetCapacity {
            if let lowestInRing = targetRingContacts.sorted(by: { $0.ringOrder > $1.ringOrder }).first {
                // Cascade: move lowest to next ring
                let nextRing = Ring.from(ringOrder: lowestInRing.ringOrder + Int16(targetCapacity) + 1)
                lowestInRing.ringOrder = Int16(targetRing.cumulativeCapacity + 1)
                lowestInRing.ring = nextRing.rawValue
                affected.append(lowestInRing)
            }
        }

        // Insert contact at target position
        contact.ringOrder = to
        contact.ring = targetRing.rawValue
        affected.append(contact)

        // Shift intermediate contacts if needed
        let shifter = try reorderIfNeeded(in: targetRing)
        affected.append(contentsOf: shifter)

        return affected
    }

    /// Moving a contact DOWN (to a higher ringOrder number).
    /// Rings below can expand, so no cascade.
    private func handleMoveDown(
        _ contact: ContactEntity,
        from: Int16,
        to: Int16
    ) throws -> [ContactEntity] {
        let targetRing = Ring.from(ringOrder: to)
        contact.ringOrder = to
        contact.ring = targetRing.rawValue

        // Shift if needed
        return try reorderIfNeeded(in: targetRing)
    }

    /// Reorder all contacts in a ring so ringOrder values are sequential.
    private func reorderIfNeeded(in ring: Ring) throws -> [ContactEntity] {
        let contacts = try fetchContactsInRing(ring).sorted { $0.ringOrder < $1.ringOrder }
        var affected: [ContactEntity] = []

        // For MVP: just ensure ring assignment is correct
        for contact in contacts {
            if contact.ring != ring.rawValue {
                contact.ring = ring.rawValue
                affected.append(contact)
            }
        }
        return affected
    }

    /// Fetch all contacts currently in a specific ring.
    private func fetchContactsInRing(_ ring: Ring) throws -> [ContactEntity] {
        let request: NSFetchRequest<ContactEntity> = ContactEntity.fetchRequest()
        request.predicate = NSPredicate(format: "ring == %d AND isPrimaryForSouvenir == YES", ring.rawValue)
        return try viewContext.fetch(request)
    }
}

