import SwiftUI
import CoreData
import UIKit

/// Rings view: Displays contacts organized by ring, with drag-to-reorder.
/// Contacts are ordered by ringOrder (chronological), grouped by Ring (Trunk, Limb, Leaf).
struct RingsView: View {
    @Environment(\.managedObjectContext) private var viewContext
    @EnvironmentObject private var router: Router

    @FetchRequest(
        sortDescriptors: [NSSortDescriptor(keyPath: \BondEntity.ringOrder, ascending: true)],
        predicate: NSPredicate(format: "owner.isSelf == YES"),
        animation: .default
    )
    private var bonds: FetchedResults<BondEntity>

    @FetchRequest(
        sortDescriptors: [],
        predicate: NSPredicate(format: "isSelf == YES"),
        animation: .default
    )
    private var selfContacts: FetchedResults<ContactEntity>

    @State private var selectedConnection: ContactEntity?
    @State private var showConnectionSheet = false
    @State private var draggingBond: BondEntity?
    @State private var dragOffset: CGFloat = 0
    @State private var dragStartRingOrder: Int16 = 0

    private typealias Tokens = DesignTokens

    private var selfContact: ContactEntity? {
        return selfContacts.first
    }

    private var bondsByRing: [Ring: [BondEntity]] {
        var grouped: [Ring: [BondEntity]] = [:]
        for ring in Ring.allCases {
            grouped[ring] = bonds.filter { $0.ring == ring.rawValue }
                .sorted { $0.ringOrder < $1.ringOrder }
        }
        return grouped
    }

    var body: some View {
        List {
            ForEach(Ring.allCases, id: \.self) { ring in
                let ringBonds = bondsByRing[ring] ?? []
                if !ringBonds.isEmpty {
                    Section {
                        ForEach(ringBonds, id: \.id) { bond in
                            if let contact = bond.contact {
                                bondRow(bond: bond, contact: contact)
                            }
                        }
                    } header: {
                        HStack {
                            Text("\(ring.label) (\(ringBonds.count)/\(ring.capacity))")
                                .font(.headline.weight(.semibold))
                                .foregroundStyle(.secondary)

                            if ring == .trunk || ring == .limb {
                                Image(systemName: "info.circle.fill")
                                    .font(.caption)
                                    .foregroundStyle(.tertiary)
                                    .help("Ring members can see you placed them here")
                            }
                        }
                    }
                    .listRowBackground(Color.clear)
                    .listRowSeparator(.hidden)
                }
            }
        }
        .svnrNavigationStyle()
        .scrollContentBackground(.hidden)
        .background(.ultraThinMaterial)
        .toolbar {
            ToolbarItem(placement: .topBarLeading) {
                Button {
                    NotificationCenter.default.post(name: .svnrRequestCamera, object: nil)
                } label: {
                    Image(systemName: "person.2.crop.square.stack")
                        .svnrSymbolPalette()
                }
                .buttonStyle(TransparentButtonStyle())
            }

            ToolbarItem(placement: .principal) {
                Text("Your Forest")
                    .font(.headline.weight(.semibold))
            }

            ToolbarItemGroup(placement: .topBarTrailing) {
                // DevTools
                Button {
                    router.navigate(to: .devTools)
                } label: {
                    Image(systemName: "gearshape")
                        .svnrSymbolPalette()
                }
                .buttonStyle(TransparentButtonStyle())

                // Rings link (active state)
                Button {
                    // Already on rings view
                } label: {
                    Image(systemName: "circle.dotted.and.circle")
                        .svnrSymbolPalette()
                }
                .buttonStyle(TransparentButtonStyle())
                .foregroundStyle(.accent)
            }
        }
        .sheet(isPresented: $showConnectionSheet) {
            if let contact = selectedConnection {
                RingsConnectionSheet(contact: contact)
            }
        }
    }

    @ViewBuilder
    private func bondRow(bond: BondEntity, contact: ContactEntity) -> some View {
        let isDragging = draggingBond?.id == bond.id

        HStack(spacing: Tokens.Spacing.small) {
            // Drag handle
            Image(systemName: "line.3.horizontal")
                .font(.body)
                .foregroundStyle(isDragging ? .accent : .secondary)
                .frame(width: 24)
                .contentShape(Rectangle())
                .gesture(
                    DragGesture()
                        .onChanged { value in
                            if draggingBond == nil {
                                draggingBond = bond
                                dragStartRingOrder = bond.ringOrder
                                dragOffset = 0
                            }
                            dragOffset = value.translation.height
                        }
                        .onEnded { _ in
                            if draggingBond?.id == bond.id {
                                handleDragEnd(bond: bond)
                            }
                        }
                )

            // Contact thumbnail
            if let data = contact.imageThumbData,
               let image = UIImage(data: data) {
                Image(uiImage: image)
                    .resizable()
                    .scaledToFill()
                    .frame(width: 36, height: 36)
                    .clipShape(Circle())
            } else {
                Circle()
                    .fill(.ultraThinMaterial)
                    .frame(width: 36, height: 36)
            }

            // Contact name
            Text(contact.displayName)
                .font(.subheadline.weight(.medium))
                .foregroundStyle(.primary)

            Spacer()

            // Branch symbol (navigate to their rings)
            Button {
                router.navigate(to: .contactRings(contactID: contact.id))
            } label: {
                Image(systemName: "arrow.trianglehead.branch")
                    .font(.body)
                    .foregroundStyle(.secondary)
                    .frame(width: 24)
            }
            .buttonStyle(.plain)
        }
        .contentShape(Rectangle())
        .padding(.vertical, 6)
        .offset(y: isDragging ? dragOffset : 0)
        .opacity(isDragging ? 0.8 : 1.0)
        .scaleEffect(isDragging ? 1.02 : 1.0, anchor: .center)
        .shadow(color: isDragging ? Color.black.opacity(0.15) : Color.clear, radius: isDragging ? 8 : 0)
        .rotation3DEffect(
            isDragging ? .degrees(Double(dragOffset) * 0.02) : .zero,
            axis: (x: 0, y: 1, z: 0),
            perspective: 1.0
        )
        .listRowBackground(Color.clear)
        .listRowSeparator(.hidden)
        .onTapGesture {
            // Tapping the thumbnail opens souvenir or connection sheet
            if let souvenirID = contact.primarySouvenir?.id {
                router.navigate(to: .souvenir(id: souvenirID))
            } else {
                selectedConnection = contact
                showConnectionSheet = true
            }
        }
    }

    private func handleDragEnd(contact: ContactEntity) {
        defer {
            draggingContact = nil
            dragOffset = 0
            dragStartRingOrder = 0
        }

        // Calculate new ring order based on drag offset
        // Each row is approximately 48pt tall (36pt photo + 12pt padding)
        let rowHeight: CGFloat = 48
        let rowsScrolled = Int(dragOffset / rowHeight)
        let newRingOrder = Int16(max(1, Int(dragStartRingOrder) - rowsScrolled))

        guard newRingOrder != dragStartRingOrder else { return }

        // Use the service to handle reordering with cascade
        let service = RingOrderService(viewContext: viewContext)

        do {
            _ = try service.reorderContact(
                contact,
                from: dragStartRingOrder,
                to: newRingOrder
            )

            // Save changes to persist
            try viewContext.save()
        } catch {
            print("❌ Failed to reorder contact: \(error)")
        }
    }
}

