import SwiftUI
import CoreData
import UIKit

/// View showing a specific contact's rings (how they've organized their contacts).
/// Shows their Trunk and Limbs rings; allows recursive navigation to their contacts' rings.
struct ContactRingsView: View {
    @Environment(\.managedObjectContext) private var viewContext
    @EnvironmentObject private var router: Router

    let contactID: UUID

    @State private var contact: ContactEntity?
    @State private var trunkBonds: [BondEntity] = []
    @State private var limbBonds: [BondEntity] = []
    @State private var isLoading = true

    private typealias Tokens = DesignTokens

    var body: some View {
        Group {
            if isLoading {
                ProgressView()
                    .frame(maxWidth: .infinity, maxHeight: .infinity)
            } else if let contact {
                List {
                    // Trunk section
                    if !trunkBonds.isEmpty || trunkBonds.count == 0 {
                        Section {
                            if trunkBonds.isEmpty {
                                Text("\(contact.givenName ?? "They") haven't placed anyone in their Trunk yet")
                                    .font(.caption)
                                    .foregroundStyle(.secondary)
                            } else {
                                ForEach(trunkBonds, id: \.id) { bond in
                                    if let member = bond.contact {
                                        contactRowForMember(member)
                                    }
                                }
                            }
                        } header: {
                            HStack {
                                Text("Their Trunk (\(trunkBonds.count)/5)")
                                    .font(.headline.weight(.semibold))
                                    .foregroundStyle(.secondary)
                                Image(systemName: "info.circle.fill")
                                    .font(.caption)
                                    .foregroundStyle(.tertiary)
                            }
                        }
                        .listRowBackground(Color.clear)
                        .listRowSeparator(.hidden)
                    }

                    // Limbs section
                    if !limbBonds.isEmpty {
                        Section {
                            ForEach(limbBonds, id: \.id) { bond in
                                if let member = bond.contact {
                                    contactRowForMember(member)
                                }
                            }
                        } header: {
                            Text("Their Limbs (\(limbBonds.count)/15)")
                                .font(.headline.weight(.semibold))
                                .foregroundStyle(.secondary)
                        }
                        .listRowBackground(Color.clear)
                        .listRowSeparator(.hidden)
                    }
                }
                .svnrNavigationStyle()
                .scrollContentBackground(.hidden)
                .background(.ultraThinMaterial)
            } else {
                Text("Contact not found")
                    .foregroundStyle(.secondary)
            }
        }
        .navigationTitle("\(contact?.displayName ?? "Forest") 🌳")
        .navigationBarTitleDisplayMode(.inline)
        .onAppear {
            loadContact()
            loadRings()
        }
    }

    @ViewBuilder
    private func contactRowForMember(_ member: ContactEntity) -> some View {
        HStack(spacing: Tokens.Spacing.small) {
            // Member thumbnail
            if let data = member.imageThumbData,
               let image = UIImage(data: data) {
                Image(uiImage: image)
                    .resizable()
                    .scaledToFill()
                    .frame(width: 36, height: 36)
                    .clipShape(Circle())
            } else {
                Circle()
                    .fill(.ultraThinMaterial)
                    .frame(width: 36, height: 36)
            }

            // Member name
            Text(member.displayName)
                .font(.subheadline.weight(.medium))
                .foregroundStyle(.primary)

            Spacer()

            // Branch symbol to navigate deeper
            Button {
                router.navigate(to: .contactRings(contactID: member.id))
            } label: {
                Image(systemName: "arrow.trianglehead.branch")
                    .font(.body)
                    .foregroundStyle(.secondary)
                    .frame(width: 24)
            }
            .buttonStyle(.plain)
        }
        .contentShape(Rectangle())
        .padding(.vertical, 6)
        .listRowBackground(Color.clear)
        .listRowSeparator(.hidden)
    }

    private func loadContact() {
        let request: NSFetchRequest<ContactEntity> = ContactEntity.fetchRequest()
        request.predicate = NSPredicate(format: "id == %@", contactID as CVarArg)
        request.fetchLimit = 1

        do {
            contact = try viewContext.fetch(request).first
        } catch {
            print("❌ Failed to load contact: \(error)")
        }

        isLoading = false
    }

    private func loadRings() {
        guard let contact else { return }

        let trunkRequest: NSFetchRequest<BondEntity> = BondEntity.fetchRequest()
        trunkRequest.predicate = NSPredicate(
            format: "owner == %@ AND ring == %d",
            contact,
            Ring.trunk.rawValue
        )
        trunkRequest.sortDescriptors = [NSSortDescriptor(keyPath: \BondEntity.ringOrder, ascending: true)]

        let limbRequest: NSFetchRequest<BondEntity> = BondEntity.fetchRequest()
        limbRequest.predicate = NSPredicate(
            format: "owner == %@ AND ring == %d",
            contact,
            Ring.limb.rawValue
        )
        limbRequest.sortDescriptors = [NSSortDescriptor(keyPath: \BondEntity.ringOrder, ascending: true)]

        do {
            trunkBonds = try viewContext.fetch(trunkRequest)
            limbBonds = try viewContext.fetch(limbRequest)
        } catch {
            print("❌ Failed to load rings: \(error)")
        }
    }
}

