private func resetOnboarding() {
    resetStatus = ""
    Task {
        do {
            try await clearAllData()
            await MainActor.run {
                // Reset all onboarding flags
                hasSavedFirstSouvenir = false
                hasPlayedIntro = false
                hasTappedSouvenirButton = false
                resetStatus = "✅ Onboarding reset"
            }
        } catch {
            await MainActor.run {
