#if DEBUG
import UIKit
import SwiftUI
@preconcurrency import CoreData

struct DevToolsView: View {
    @State private var exportURL: URL?
    @State private var isSharing = false
    @State private var exportStatus: String = ""
    @State private var isExporting = false
    @State private var importStatus: String = ""
    @State private var isImporting = false
    @State private var showImportConfirmation = false
    @State private var showResetOnboardingConfirmation = false
    @State private var resetStatus: String = ""
    @State private var showNukeConfirmation = false
    @State private var nukeStatus: String = ""

    @Environment(\.managedObjectContext) private var viewContext
    @AppStorage("svnrHasSavedFirstSouvenir") private var hasSavedFirstSouvenir = false
    @AppStorage("svnrOnboardingIntroHasPlayed") private var hasPlayedIntro = false
    @AppStorage("svnrOnboardingHasTappedSouvenir") private var hasTappedSouvenirButton = false

    let container: NSPersistentContainer

    var body: some View {
        Form {
            Section("Admin") {
                NavigationLink("Paired Invite") {
                    AdminDualInviteView(container: container)
                }
            }

            Section {
                VStack(alignment: .leading, spacing: 12) {
                    Text("Delete all Core Data records and propagate deletes to CloudKit. Resets to a blank slate.")
                        .font(.caption)
                        .foregroundStyle(.secondary)

                    Button(role: .destructive) {
                        showNukeConfirmation = true
                    } label: {
                        HStack {
                            Image(systemName: "trash.fill")
                            .svnrSymbolPalette()
                            Text("Nuke All Data")
                        }
                    }

                    if !nukeStatus.isEmpty {
                        Text(nukeStatus)
                            .font(.caption)
                            .foregroundColor(nukeStatus.hasPrefix("✅") ? Color.successSvnr : Color.dangerSvnr)
                    }
                }
            } header: {
                Text("Fresh Start")
            }

            Section {
                VStack(alignment: .leading, spacing: 12) {
                    Text("Clear all data to re-run onboarding.")
                        .font(.caption)
                        .foregroundStyle(.secondary)

                    Button(role: .destructive) {
                        showResetOnboardingConfirmation = true
                    } label: {
                        HStack {
                            Image(systemName: "arrow.counterclockwise")
                            .svnrSymbolPalette()
                            Text("Reset Onboarding")
                        }
                    }

                    if !resetStatus.isEmpty {
                        Text(resetStatus)
                            .font(.caption)
                            .foregroundColor(resetStatus.hasPrefix("✅") ? Color.successSvnr : Color.dangerSvnr)
                    }
                }
            } header: {
                Text("Onboarding")
            }

            Section {
                VStack(alignment: .leading, spacing: 12) {
                    Text("Import seed data from bundled JSON file. This will clear existing data and import from SeedData/seed.json with bundled images.")
                        .font(.caption)
                        .foregroundStyle(.secondary)

                    Button(role: .destructive) {
                        showImportConfirmation = true
                    } label: {
                        HStack {
                            Image(systemName: "square.and.arrow.down")
                            .svnrSymbolPalette()
                            Text("Import Seed Data")

                            if isImporting {
                                Spacer()
                                ProgressView()
                                    .controlSize(.small)
                            }
                        }
                    }
                    .disabled(isImporting)

                    if !importStatus.isEmpty {
                        Text(importStatus)
                            .font(.caption)
                            .foregroundColor(importStatus.hasPrefix("✅") ? Color.successSvnr : Color.dangerSvnr)
                    }
                }
            } header: {
                Text("Data Import")
            }

            Section {
                VStack(alignment: .leading, spacing: 12) {
                    Text("Export all Core Data entities to JSON format. Use this to backup data or seed test environments.")
                        .font(.caption)
                        .foregroundStyle(.secondary)

                    Button {
                        exportData()
                    } label: {
                        HStack {
                            Image(systemName: "square.and.arrow.up")
                            .svnrSymbolPalette()
                            Text("Export Core Data to JSON")

                            if isExporting {
                                Spacer()
                                ProgressView()
                                    .controlSize(.small)
                            }
                        }
                    }
                    .disabled(isExporting)

                    if !exportStatus.isEmpty {
                        Text(exportStatus)
                            .font(.caption)
                            .foregroundColor(exportStatus.hasPrefix("✅") ? Color.successSvnr : Color.dangerSvnr)
                    }
                }
            } header: {
                Text("Data Export")
            }

            if let url = exportURL {
                Section {
                    HStack {
                        VStack(alignment: .leading, spacing: 4) {
                            Text("Last Export")
                                .font(.caption)
                                .foregroundStyle(.secondary)
                            Text(url.lastPathComponent)
                                .font(.footnote)
                                .fontWeight(.medium)
                        }

                        Spacer()

                        Button {
                            isSharing = true
                        } label: {
                            Image(systemName: "square.and.arrow.up")
                            .svnrSymbolPalette()
                        }
                    }
                } header: {
                    Text("Recent Export")
                }
            }
            Section {
                statsRow(label: "Souvenirs", count: countEntities(SouvenirEntity.self))
                statsRow(label: "Contacts", count: countEntities(ContactEntity.self))
                statsRow(label: "Photos", count: countEntities(PhotoEntity.self))
                statsRow(label: "Shares", count: countEntities(ShareEntity.self))
            } header: {
                Text("Database Stats")
            }

            BundleDebugView()
        }
        .sheet(isPresented: $isSharing) {
            if let url = exportURL {
                FileShareSheet(activityItems: [url])
            }
        }
        .confirmationDialog(
            "Import Seed Data",
            isPresented: $showImportConfirmation,
            titleVisibility: .visible
        ) {
            Button("Import and Replace All Data", role: .destructive) {
                importSeedData()
            }
            Button("Cancel", role: .cancel) {}
        } message: {
            Text("This will delete all existing data and import from the bundled seed.json file. This cannot be undone.")
        }
        .confirmationDialog(
            "Reset Onboarding",
            isPresented: $showResetOnboardingConfirmation,
            titleVisibility: .visible
        ) {
            Button("Clear All Data", role: .destructive) {
                resetOnboarding()
            }
            Button("Cancel", role: .cancel) {}
        } message: {
            Text("This will delete all existing data. This cannot be undone.")
        }
        .confirmationDialog(
            "Nuke All Data",
            isPresented: $showNukeConfirmation,
            titleVisibility: .visible
        ) {
            Button("Delete Everything", role: .destructive) {
                nukeAllData()
            }
            Button("Cancel", role: .cancel) {}
        } message: {
            Text("Deletes all records locally and syncs the deletes to CloudKit. The app will restart in a blank state.")
        }
    }

    private func statsRow(label: String, count: Int) -> some View {
        HStack {
            Text(label)
            Spacer()
            Text("\(count)")
                .foregroundStyle(.secondary)
                .fontWeight(.medium)
        }
    }

    private func countEntities<T: NSManagedObject>(_ type: T.Type) -> Int {
        let request = NSFetchRequest<T>(entityName: String(describing: type))
        return (try? viewContext.count(for: request)) ?? 0
    }

    private func exportData() {
        isExporting = true
        exportStatus = ""

        Task {
            do {
                let docs = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first!
                let timestamp = ISO8601DateFormatter().string(from: Date()).replacingOccurrences(of: ":", with: "-")
                let dest = docs.appendingPathComponent("souvenir_export_\(timestamp).json")

                try exportCoreDataToJSON(container: container, to: dest)

                await MainActor.run {
                    exportURL = dest
                    exportStatus = "✅ Exported \(dest.lastPathComponent)"
                    isExporting = false
                    isSharing = true
                }
            } catch {
                await MainActor.run {
                    exportStatus = "❌ Export failed: \(error.localizedDescription)"
                    isExporting = false
                }
                print("❌ Export failed: \(error)")
            }
        }
    }

    private func importSeedData() {
        isImporting = true
        importStatus = ""

        Task {
            do {
                // Find bundled seed.json
                guard let seedURL = Bundle.main.url(forResource: "seed", withExtension: "json", subdirectory: "SeedData") else {
                    throw ImportError.invalidFormat
                }

                // Clear existing data
                try await clearAllData()

                // Import from JSON with seed images
                try await importCoreDataFromJSON(
                    container: container,
                    jsonURL: seedURL,
                    seedImagesFolder: "SeedData/Images"
                )

                await MainActor.run {
                    // Reset onboarding flags since we're importing data
                    hasSavedFirstSouvenir = true
                    hasPlayedIntro = true
                    importStatus = "✅ Successfully imported seed data"
                    isImporting = false
                }
            } catch {
                await MainActor.run {
                    importStatus = "❌ Import failed: \(error.localizedDescription)"
                    isImporting = false
                }
                print("❌ Import failed: \(error)")
            }
        }
    }

    private func resetOnboarding() {
        resetStatus = ""
        Task {
            do {
                try await clearAllData()
                await MainActor.run {
                    // Reset all onboarding flags
                    hasSavedFirstSouvenir = false
                    hasPlayedIntro = false
                    hasTappedSouvenirButton = false
                    resetStatus = "✅ Onboarding reset"
                }
            } catch {
                await MainActor.run {
                    resetStatus = "❌ Reset failed: \(error.localizedDescription)"
                }
            }
        }
    }

    /// Deletes all records via the managed object context so NSPersistentCloudKitContainer
    /// tracks the deletes and propagates them to iCloud.
    private func nukeAllData() {
        nukeStatus = ""
        Task {
            do {
                let ctx = container.viewContext
                try await ctx.perform {
                    ctx.userInfo["svnrSkipDeleteValidation"] = true
                    ctx.userInfo["svnrSkipUpdateValidation"] = true
                    defer {
                        ctx.userInfo["svnrSkipDeleteValidation"] = nil
                        ctx.userInfo["svnrSkipUpdateValidation"] = nil
                    }
                    // Phase 1: clear all blocking relationships so validateForDelete passes.
                    // • SouvenirEntity throws if hasActiveShares
                    // • ContactEntity throws if primarySouvenir != nil
                    // • PhotoEntity throws if favoritedBySouvenir != nil or is souvenir's only photo
                    let souvenirReq = NSFetchRequest<SouvenirEntity>(entityName: "SouvenirEntity")
                    let souvenirs = try ctx.fetch(souvenirReq)
                    for s in souvenirs {
                        s.favoritePhoto = nil       // unblocks PhotoEntity.validateForDelete
                        s.primaryContact = nil      // unblocks ContactEntity.validateForDelete
                        s.photos = nil              // clears photo→souvenir inverse
                        s.shares = nil              // unblocks SouvenirEntity.validateForDelete
                    }
                    try ctx.save()

                    // Phase 2: delete everything — validators all pass now.
                    for entityName in ["VouchEntity", "ShareEntity", "PhotoEntity", "ContactEntity", "SouvenirEntity"] {
                        let req = NSFetchRequest<NSManagedObject>(entityName: entityName)
                        let objects = try ctx.fetch(req)
                        objects.forEach { ctx.delete($0) }
                    }
                    try ctx.save()
                }
                await MainActor.run {
                    hasSavedFirstSouvenir = false
                    hasPlayedIntro = false
                    hasTappedSouvenirButton = false
                    nukeStatus = "✅ All data cleared — CloudKit sync pending"
                }
            } catch {
                await MainActor.run {
                    nukeStatus = "❌ Nuke failed: \(error.localizedDescription)"
                }
            }
        }
    }

    private func clearAllData() async throws {
        await container.viewContext.perform {
            self.container.viewContext.rollback()
        }
        let entityNames = ["BondEntity", "SouvenirEntity", "ContactEntity", "PhotoEntity", "ShareEntity", "VouchEntity"]

        for entityName in entityNames {
            let fetchRequest = NSFetchRequest<NSFetchRequestResult>(entityName: entityName)
            let deleteRequest = NSBatchDeleteRequest(fetchRequest: fetchRequest)

            _ = try await container.viewContext.perform {
                try self.container.viewContext.execute(deleteRequest)
            }
        }

        try await container.viewContext.perform {
            try self.container.viewContext.save()
        }
    }
}

/// A debug view to inspect bundle contents at runtime
struct BundleDebugView: View {
    @State private var bundleContents: String = "Inspecting..."

    var body: some View {
        Section(header: Text("Bundle Contents Inspector")) {
            Text(bundleContents)
                .font(.system(.caption, design: .monospaced))
                .onAppear(perform: inspectBundle)
        }
    }

    func inspectBundle() {
        let bundleURL = Bundle.main.bundleURL
        var output = "Bundle Path: \(bundleURL.path)\n\n"

        guard let enumerator = FileManager.default.enumerator(at: bundleURL, includingPropertiesForKeys: nil, options: [.skipsHiddenFiles], errorHandler: nil) else {
            bundleContents = "Failed to create bundle enumerator."
            return
        }

        var found = false
        for case let fileURL as URL in enumerator {
            let relativePath = fileURL.path.replacingOccurrences(of: bundleURL.path, with: "")
            if relativePath.contains("seed.json") {
                found = true
            }
            output += "\(relativePath)\n"
        }

        if !found {
            output = "seed.json NOT FOUND IN BUNDLE\n\n" + output
        }

        bundleContents = output
    }
}

