import SwiftUI
import PhotosUI
import Photos
import UIKit

/// Main view mode toggle state
enum MainViewMode: String, CaseIterable {
    case timeline
    case map

    var icon: String {
        switch self {
        case .timeline: return "calendar"
        case .map: return "map"
        }
    }
