/// Floating camera shutter button with Liquid Glass styling.
/// Positioned bottom-center on ListView and MapView.
struct BottomNavBar: View {
    @Binding var viewMode: MainViewMode
    @Binding var showCamera: Bool
    @Binding var selectedPhoto: PhotosPickerItem?

    @Environment(\.colorScheme) private var colorScheme

    var body: some View {
        VStack {
            Spacer()
            floatingShutterButton
        }
    }

    private var floatingShutterButton: some View {
        Button {
            showCamera = true
        } label: {
            EmptyView()
        }
        .buttonStyle(FloatingShutterButtonStyle())
        .accessibilityLabel("Take photo")
    }
}

// MARK: - Floating Shutter Button Style

/// iOS 26 Liquid Glass style floating shutter button with triple-ring design
struct FloatingShutterButtonStyle: ButtonStyle {
    @Environment(\.colorScheme) private var colorScheme
    @Environment(\.accessibilityReduceMotion) private var reduceMotion

    func makeBody(configuration: Configuration) -> some View {
        let isPressed = configuration.isPressed
        let isDark = (colorScheme == .dark)

        ZStack {
            // Outer "glow" ring - regularMaterial, 4pt thick
            Circle()
                .fill(.regularMaterial)
                .frame(
                    width: DesignTokens.Size.shutterButtonOuter + 12,
                    height: DesignTokens.Size.shutterButtonOuter + 12
                )
                .overlay(
                    Circle()
                        .strokeBorder(
                            isDark ? Color.white.opacity(DesignTokens.Opacity.medium) : Color.white.opacity(DesignTokens.Opacity.semi),
                            lineWidth: 1
                        )
                )
                .shadow(color: .black.opacity(0.2), radius: isPressed ? 4 : 8, x: 0, y: isPressed ? 2 : 4)

            // Middle "glass" ring with Liquid Glass styling
            Circle()
                .fill(isDark ? .regularMaterial : .ultraThinMaterial)
                .overlay(
                    Circle()
                        .strokeBorder(
                            isDark ? Color.white.opacity(DesignTokens.Opacity.nearlyOpaque) : Color.white.opacity(DesignTokens.Opacity.strong),
                            lineWidth: 2
                        )
                )
                .frame(width: DesignTokens.Size.shutterButtonOuter, height: DesignTokens.Size.shutterButtonOuter)

            // Inner disc
            Circle()
                .fill(.thinMaterial)
                .scaleEffect(isPressed ? 0.9 : 1.0)
                .frame(width: DesignTokens.Size.shutterButtonInner, height: DesignTokens.Size.shutterButtonInner)

            // Icon
            Image(systemName: "person.2.crop.square.stack")
                .foregroundStyle(.primary)
                .font(.system(size: DesignTokens.Size.buttonIcon, weight: .medium))
            .svnrSymbolPalette()
        }
        .scaleEffect(isPressed ? 0.95 : 1.0)
        .animation(reduceMotion ? nil : DesignTokens.Animation.buttonPress, value: isPressed)
    }
}

