import SwiftUI

struct MapListToggle: View {
    @Binding var viewMode: MainViewMode
    @Environment(\.accessibilityReduceMotion) private var reduceMotion
    @GestureState private var dragTranslation: CGFloat = 0
    @State private var totalWidth: CGFloat = 0
    @State private var segmentWidth: CGFloat = 0

    private let pillHeight: CGFloat = 40
    private let glyphSize: CGFloat = 22
    private let horizontalPadding: CGFloat = DesignTokens.Spacing.medium
    private let itemSpacing: CGFloat = DesignTokens.Spacing.medium
    private let offsetMiscalculation: CGFloat = 6

    var body: some View {
        baseStack
            .overlay(alignment: .leading) {
                overlayStack
            }
            .onPreferenceChange(TotalWidthKey.self) { totalWidth = $0 }
            .onPreferenceChange(SegmentWidthKey.self) { segmentWidth = $0 }
            .contentShape(Capsule())
            .gesture(dragGesture)
            .onTapGesture { toggleMode() }
            .accessibilityAddTraits(.isButton)
            .accessibilityLabel(viewMode == .map ? "Switch to list view" : "Switch to map view")
            .accessibilityValue(viewMode == .map ? "Map" : "List")
    }

    private var baseStack: some View {
        ZStack(alignment: .leading) {
            indicatorPill
            mainContent
        }
    }

    private var indicatorPill: some View {
        Capsule()
            .fill(.thinMaterial)
            .frame(width: segmentWidth, height: pillHeight)
            .offset(x: currentOffset)
            .shadow(color: Color.black.opacity(0.16), radius: 5, x: 0, y: 2)
    }

    private var mainContent: some View {
        HStack(spacing: itemSpacing) {
            Image(viewMode == .map ? "svnr-glyph-line2" : "svnr-glyph-fill")
                .resizable()
                .scaledToFit()
                .frame(width: glyphSize, height: glyphSize)
            svnrLabel
            Image(systemName: viewMode == .map ? "mappin.and.ellipse.circle.fill" : "mappin.and.ellipse.circle")
                .font(.title2)
                .fontWeight(.regular)
        }
        .foregroundStyle(.primary)
        .padding(.horizontal, horizontalPadding)
        .background(WidthReader(key: TotalWidthKey.self))
    }

    private var overlayStack: some View {
        HStack(spacing: itemSpacing) {
            Image("svnr-glyph-line2")
                .resizable()
                .scaledToFit()
                .frame(width: glyphSize, height: glyphSize)
            svnrLabel
        }
        .padding(.horizontal, horizontalPadding)
        .background(WidthReader(key: SegmentWidthKey.self))
        .opacity(0.001)
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 6)
            .updating($dragTranslation) { value, state, _ in
                state = value.translation.width
            }
            .onEnded { value in
                guard rightOffset > leftOffset else { return }
                let projected = targetOffset + value.predictedEndTranslation.width
                let clamped = clamp(projected, min: leftOffset, max: rightOffset)
                let midpoint = (leftOffset + rightOffset) / 2
                let newMode: MainViewMode = clamped >= midpoint ? .map : .timeline
                setMode(newMode)
            }
    }

    private var svnrLabel: some View {
        Text("SVNR")
            .font(.title.weight(.heavy))
            .fontDesign(.rounded)
    }

    private var leftOffset: CGFloat {
        0
    }

    private var rightOffset: CGFloat {
        max(0, totalWidth - segmentWidth - offsetMiscalculation)
    }

    private var targetOffset: CGFloat {
        viewMode == .map ? rightOffset : leftOffset
    }

    private var currentOffset: CGFloat {
        clamp(targetOffset + dragTranslation, min: leftOffset, max: rightOffset)
    }

    private func toggleMode() {
        setMode(viewMode == .map ? .timeline : .map)
    }

    private func setMode(_ newMode: MainViewMode) {
        if reduceMotion {
            viewMode = newMode
        } else {
            withAnimation(DesignTokens.Animation.viewModeSwitch) {
                viewMode = newMode
            }
        }
    }

    private func clamp(_ value: CGFloat, min: CGFloat, max: CGFloat) -> CGFloat {
        Swift.max(min, Swift.min(max, value))
    }
}

