import Foundation

public enum Ring: Int16, CaseIterable {
    case trunk = 1   // 5 contacts max
    case limb  = 2   // 15 contacts max
    case leaf  = 3   // 45+ contacts max

    public var label: String {
        switch self {
        case .trunk:
            return "Trunk"
        case .limb:
            return "Limbs"
        case .leaf:
            return "Leaves"
        }
    }

    public var capacity: Int {
        switch self {
        case .trunk:
            return 5
        case .limb:
            return 15
        case .leaf:
            return 45
        }
    }

    public var weight: Double {
        switch self {
        case .trunk:
            return 4.0
        case .limb:
            return 2.0
        case .leaf:
            return 1.0
        }
    }

    public var isPublishedByDefault: Bool {
        switch self {
        case .trunk, .limb:
            return true
        case .leaf:
            return false
        }
    }

    /// Compute ring from ringOrder position (1-indexed)
    public static func from(ringOrder: Int16) -> Ring {
        if ringOrder <= 5 {
            return .trunk
        } else if ringOrder <= 20 {
            return .limb
        } else {
            return .leaf
        }
    }

    /// Cumulative capacity up to and including this ring
    public var cumulativeCapacity: Int {
        switch self {
        case .trunk:
            return 5
        case .limb:
            return 20  // 5 + 15
        case .leaf:
            return 150 // 5 + 15 + 130+ (or more)
        }
    }
}

